import{_ as e,o as i,c as r,ah as l}from"./chunks/framework.CkJUk41Q.js";const C=JSON.parse('{"title":"C#","description":"","frontmatter":{"title":"C#","order":50},"headers":[],"relativePath":"client/csharp/index.md","filePath":"client/csharp/index.md"}'),t={name:"client/csharp/index.md"};function n(s,a,o,c,h,d){return i(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="c" tabindex="-1">C# <a class="header-anchor" href="#c" aria-label="Permalink to “C#”">​</a></h1><p>C# 是由微软在 2000 年发布的现代编程语言，由 Anders Hejlsberg 领导设计，他是 Turbo Pascal 和 Delphi 的首席架构师。C# 的设计目标是成为一种简单、现代、通用的面向对象编程语言，同时兼顾 C++ 的强大功能和 Visual Basic 的易用性。</p><h2 id="语言特性" tabindex="-1">语言特性 <a class="header-anchor" href="#语言特性" aria-label="Permalink to “语言特性”">​</a></h2><p>C# 运行在 .NET 运行时之上，编译为中间语言 (IL) 由 JIT 编译器转换为本地代码。C# 结合了 C++ 的性能和 Java 的易用性，引入了许多现代语言特性，如垃圾回收、泛型、LINQ、async/await 等。</p><p>C# 的类型系统包括值类型和引用类型。值类型直接存储数据，分配在栈上或内联在对象中；引用类型存储对象的引用，分配在托管堆上。垃圾回收器自动管理内存，开发者无需手动释放。</p><p>C# 支持多种编程范式，包括面向对象、函数式、泛型、反射等。现代 C# 版本持续引入新特性，如模式匹配、记录类型、可空引用类型等，保持语言的现代感。</p><h2 id="应用领域" tabindex="-1">应用领域 <a class="header-anchor" href="#应用领域" aria-label="Permalink to “应用领域”">​</a></h2><p>C# 在多个领域有广泛应用。Web 开发方面，ASP.NET Core 是高性能的 Web 框架，支持 MVC、Web API、Blazor 等开发模式。桌面应用方面，WinForms、WPF、WinUI 3 提供了丰富的桌面应用开发能力。游戏开发方面，Unity 引擎使用 C# 作为脚本语言，是独立游戏和手游开发的首选。云计算方面，Azure 是微软的云平台，.NET 应用可以无缝部署到 Azure。</p><h2 id="技术文章" tabindex="-1">技术文章 <a class="header-anchor" href="#技术文章" aria-label="Permalink to “技术文章”">​</a></h2><ul><li><a href="./basic">基础语法</a> - 类型系统、变量、方法、泛型、命名空间</li><li><a href="./async">异步编程</a> - async/await、Task、ValueTask、异步流、取消操作</li><li><a href="./nuget">NuGet 包管理</a> - 包结构、dotnet CLI、版本范围、私有源、包发布</li><li><a href="./dotnet">.NET 运行时</a> - JIT/AOT 编译、GC、IDisposable、线程池、异常处理</li><li><a href="./msbuild">MSBuild</a> - 项目文件、目标任务、构建配置、自定义任务</li><li><a href="./unity">Unity 脚本</a> - MonoBehaviour、协程、组件系统、物理、预制体</li></ul>',10)])])}const _=e(t,[["render",n]]);export{C as __pageData,_ as default};
